<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;
class FoodOrder extends Model{use Concerns\BelongsToHotel;protected $fillable=['hotel_id','guest_id','checkin_id','room_id','number','status','payment_method','subtotal','tax_total','total','notes','accepted_at','ready_at','delivered_at','cancelled_at','updated_by'];protected function casts():array{return['subtotal'=>'decimal:2','tax_total'=>'decimal:2','total'=>'decimal:2','accepted_at'=>'datetime','ready_at'=>'datetime','delivered_at'=>'datetime','cancelled_at'=>'datetime'];}public function items(){return$this->hasMany(FoodOrderItem::class);}public function guest(){return$this->belongsTo(Guest::class);}public function room(){return$this->belongsTo(Room::class);}public function checkin(){return$this->belongsTo(Checkin::class);}}
